sql:
SELECT COUNT(DISTINCT program_id) AS program_count
FROM program_sessions
WHERE session_date > DATE('now');

SELECT COUNT(DISTINCT p.program_id) AS total_programs_with_waitlist
FROM programs p
INNER JOIN waitlists w ON p.program_id = w.program_id;

SELECT COUNT(DISTINCT user_id) AS num_enrolled
FROM enrollments
WHERE enrollment_date BETWEEN '2023-05-01' AND '2023-05-31';

SELECT program_id, COUNT(session_id) AS total_sessions
FROM program_sessions
GROUP BY program_id;

SELECT program_type, AVG(price) AS average_price
FROM programs
GROUP BY program_type;

external_knowledge:
- 'gardens' refer to 'programs';
- 'pioneers' are the users who first enrolled in the programs;
- 'cast their seeds' refers to the action of enrolling;
- 'order' in this context means the chronological order of enrollments within each program.

